import React, { useState, useEffect } from 'react';
import { useAuth } from '../utils/AuthContext';
import { cities, places } from '../utils/api';

const Home = () => {
  const { isAuthenticated, isAdmin } = useAuth();

  return (
    <div style={styles.container}>
      <div style={styles.hero}>
        <div style={styles.heroContent}>
          <div style={styles.heroText}>
            <h1 style={styles.heroTitle}>Journey Planner</h1>
            <p style={styles.heroSubtitle}>
              Plan your perfect trip to Nepal's beautiful cities with budget optimization
            </p>

            {!isAuthenticated ? (
              <div style={styles.heroActions}>
                <a href="/register" style={styles.primaryButton}>Get Started</a>
                <a href="/login" style={styles.secondaryButton}>Login</a>
              </div>
            ) : (
              <div style={styles.heroActions}>
                {isAdmin ? (
                  <a href="/admin" style={styles.primaryButton}>Admin Dashboard</a>
                ) : (
                  <a href="/places" style={styles.primaryButton}>Explore Places</a>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

const styles = {
  container: {
    minHeight: '100vh'
  },
  hero: {
    padding: '4rem 2rem',
    backgroundImage: 'url(/travel.png)',
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    backgroundRepeat: 'no-repeat',
    minHeight: '100vh',
    display: 'flex',
    alignItems: 'center'
  },
  heroContent: {
    maxWidth: '600px',
    margin: '0 auto',
    backgroundColor: 'rgba(255, 255, 255, 0.95)',
    padding: '2.5rem',
    borderRadius: '16px',
    backdropFilter: 'blur(10px)',
    boxShadow: '0 8px 32px rgba(0, 0, 0, 0.1)'
  },
  heroText: {
    textAlign: 'center'
  },
  heroTitle: {
    fontSize: '2.5rem',
    fontWeight: '800',
    color: '#1f2937',
    marginBottom: '1rem',
    fontFamily: 'system-ui, -apple-system, sans-serif'
  },
  heroSubtitle: {
    fontSize: '1.1rem',
    color: '#4b5563',
    marginBottom: '2rem',
    lineHeight: '1.6'
  },
  heroActions: {
    display: 'flex',
    gap: '1rem',
    justifyContent: 'center'
  },
  primaryButton: {
    backgroundColor: '#3b82f6',
    color: 'white',
    padding: '0.875rem 2rem',
    borderRadius: '8px',
    textDecoration: 'none',
    fontWeight: '600',
    transition: 'all 0.2s ease',
    boxShadow: '0 4px 12px rgba(59, 130, 246, 0.3)',
    fontFamily: 'system-ui, -apple-system, sans-serif'
  },
  secondaryButton: {
    backgroundColor: 'transparent',
    color: '#3b82f6',
    padding: '0.875rem 2rem',
    borderRadius: '8px',
    textDecoration: 'none',
    fontWeight: '600',
    border: '2px solid #3b82f6',
    transition: 'all 0.2s ease',
    fontFamily: 'system-ui, -apple-system, sans-serif'
  }
};

export default Home;
